<?php
$search=trim($_GET['search']??'');$deptFilter=trim($_GET['dept']??'');$statusFilter=trim($_GET['status']??'');
$totalStudents=(int)$pdo->query("SELECT COUNT(*) FROM users WHERE type='student'")->fetchColumn();
$approved=(int)$pdo->query("SELECT COUNT(*) FROM users WHERE type='student' AND status='approved'")->fetchColumn();
$pending=(int)$pdo->query("SELECT COUNT(*) FROM users WHERE type='student' AND status='pending'")->fetchColumn();
$voted=(int)$pdo->query("SELECT COUNT(DISTINCT user_id) FROM votes")->fetchColumn();
$turnout=$approved>0?round($voted/$approved*100,1):0;
$departments=$pdo->query("SELECT DISTINCT department FROM students WHERE department IS NOT NULL ORDER BY department")->fetchAll(PDO::FETCH_COLUMN);
$deptStats=$pdo->query("SELECT s.department,COUNT(DISTINCT s.user_id) AS total,COUNT(DISTINCT v.user_id) AS voted FROM students s LEFT JOIN votes v ON v.user_id=s.user_id WHERE s.department IS NOT NULL GROUP BY s.department ORDER BY total DESC")->fetchAll(PDO::FETCH_ASSOC);
$where="WHERE u.type='student'";$params=[];
if($search!==''){$where.=" AND (u.name LIKE ? OR u.email LIKE ? OR s.student_id LIKE ?)";$like="%$search%";$params[]=$like;$params[]=$like;$params[]=$like;}
if($deptFilter!==''){$where.=" AND s.department=?";$params[]=$deptFilter;}
if($statusFilter==='voted'){$where.=" AND EXISTS(SELECT 1 FROM votes vv WHERE vv.user_id=u.id)";}
elseif($statusFilter==='not_voted'){$where.=" AND NOT EXISTS(SELECT 1 FROM votes vv WHERE vv.user_id=u.id)";}
elseif($statusFilter!==''){$where.=" AND u.status=?";$params[]=$statusFilter;}
$stmt=$pdo->prepare("SELECT u.id,u.name,u.email,u.status,u.created_at,s.student_id,s.department,s.level,COUNT(DISTINCT v.id) AS votes_cast,MAX(v.created_at) AS last_voted FROM users u LEFT JOIN students s ON s.user_id=u.id LEFT JOIN votes v ON v.user_id=u.id $where GROUP BY u.id ORDER BY u.created_at DESC");
$stmt->execute($params);$participants=$stmt->fetchAll(PDO::FETCH_ASSOC);
?><!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Participants - IUC Voting</title>
