s:10px;display:flex;align-items:center;justify-content:center;font-size:1.1rem;background:linear-gradient(135deg,#3282B8,#0B3C5D);color:#fff;flex-shrink:0}.sc.g .si{background:linear-gradient(135deg,#10b981,#059669)}.sc.o .si{background:linear-gradient(135deg,#f59e0b,#d97706)}.sc.p .si{background:linear-gradient(135deg,#8b5cf6,#6d28d9)}.sc.r .si{background:linear-gradient(135deg,#ef4444,#dc2626)}.sn{font-size:1.5rem;font-weight:800;color:#1e293b;line-height:1}.sl{font-size:.72rem;color:#64748b;margin-top:.15rem}.cr{display:grid;grid-template-columns:1fr 1fr;gap:1.5rem;margin-bottom:1.5rem}.cc{background:#fff;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);overflow:hidden}.ch{padding:1rem 1.5rem;border-bottom:1px solid #f1f5f9;font-size:.9rem;font-weight:700;color:#374151;display:flex;align-items:center;gap:.5rem}.cb{padding:1.25rem}.dc{background:#fff;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);overflow:hidden;margin-bottom:1.5rem}.dr{display:flex;align-items:center;gap:.75rem;padding:.6rem 1.5rem;border-bottom:1px solid #f1f5f9}.dr:last-child{border-bottom:none}.dn{font-size:.83rem;font-weight:600;color:#374151;width:170px;flex-shrink:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.dt{flex:1;height:9px;background:#f1f5f9;border-radius:5px;overflow:hidden}.df{height:100%;border-radius:5px;background:linear-gradient(90deg,#3282B8,#0B3C5D)}.dm{font-size:.75rem;color:#64748b;width:90px;text-align:right;flex-shrink:0}.fb{background:#fff;border-radius:12px;padding:1.1rem 1.5rem;box-shadow:0 2px 8px rgba(0,0,0,.06);margin-bottom:1.5rem;display:flex;gap:.75rem;flex-wrap:wrap;align-items:flex-end}.fg{display:flex;flex-direction:column;gap:.3rem;flex:1;min-width:150px}.fg label{font-size:.72rem;font-weight:600;color:#64748b;text-transform:uppercase}.fg input,.fg select{padding:.6rem .9rem;border:2px solid #e2e8f0;border-radius:8px;font-size:.85rem;color:#1e293b;background:#fff}.fg input:focus,.fg select:focus{outline:none;border-color:#3282B8}.btn{padding:.6rem 1.1rem;border:none;border-radius:8px;font-weight:600;cursor:pointer;display:inline-flex;align-items:center;gap:.4rem;font-size:.83rem;text-decoration:none;transition:all .2s;white-space:nowrap}.bp{background:linear-gradient(135deg,#3282B8,#0B3C5D);color:#fff}.bo{background:#fff;border:2px solid #e2e8f0;color:#64748b}.tc{background:#fff;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);overflow:hidden}.th{padding:1rem 1.5rem;border-bottom:1px solid #f1f5f9;display:flex;justify-content:space-between;align-items:center}.th h3{font-size:.9rem;font-weight:700;color:#374151;display:flex;align-items:center;gap:.5rem}table{width:100%;border-collapse:collapse;font-size:.82rem}th{background:#f8fafc;padding:.6rem 1rem;text-align:left;font-weight:600;color:#374151;border-bottom:2px solid #e2e8f0;white-space:nowrap}td{padding:.6rem 1rem;border-bottom:1px solid #f1f5f9;color:#374151}tr:hover td{background:#f8fafc}.badge{padding:.2rem .55rem;border-radius:8px;font-size:.7rem;font-weight:700;text-transform:uppercase}.ba{background:#dcfce7;color:#166534}.bp2{background:#fef9c3;color:#854d0e}.br{background:#fee2e2;color:#991b1b}.bv{background:#dbeafe;color:#1e40af}.bn{background:#f1f5f9;color:#64748b}.empty{text-align:center;padding:3rem;color:#94a3b8}.empty i{font-size:2.5rem;display:block;margin-bottom:.75rem;opacity:.3}.tf{padding:.7rem 1.5rem;background:#f8fafc;border-top:1px solid #e2e8f0;font-size:.78rem;color:#64748b;display:flex;justify-content:space-between}@media(max-width:768px){.sidebar{display:none}.main{margin-left:0;padding:1rem}}</style></head>
