<div class="fg"><label>Status</label><select name="status"><option value="">All</option><option value="approved" <?= $statusFilter==='approved'?'selected':'' ?>>Approved</option><option value="pending" <?= $statusFilter==='pending'?'selected':'' ?>>Pending</option><option value="rejected" <?= $statusFilter==='rejected'?'selected':'' ?>>Rejected</option><option value="voted" <?= $statusFilter==='voted'?'selected':'' ?>>Has Voted</option><option value="not_voted" <?= $statusFilter==='not_voted'?'selected':'' ?>>Not Voted</option></select></div>
